package io.harbor.textd.core;

import java.io.IOException;
import java.nio.file.Path;
import java.util.HashMap;
import java.util.Map;
import java.util.jar.JarEntry;
import java.util.jar.JarFile;

final class PluginClassLoader extends ClassLoader implements AutoCloseable {
    private final Map<String, byte[]> classBytes;

    private PluginClassLoader(ClassLoader parent, Map<String, byte[]> classBytes) {
        super(parent);
        this.classBytes = classBytes;
    }

    static PluginClassLoader load(Path pluginJar, ClassLoader parent) throws IOException {
        Map<String, byte[]> classBytes = new HashMap<>();
        try (JarFile jarFile = new JarFile(pluginJar.toFile())) {
            for (JarEntry entry : java.util.Collections.list(jarFile.entries())) {
                if (entry.isDirectory() || !entry.getName().endsWith(".class")) {
                    continue;
                }
                String className = entry.getName()
                    .substring(0, entry.getName().length() - ".class".length())
                    .replace('/', '.');
                classBytes.put(className, jarFile.getInputStream(entry).readAllBytes());
            }
        }
        return new PluginClassLoader(parent, classBytes);
    }

    @Override
    protected Class<?> findClass(String name) throws ClassNotFoundException {
        byte[] bytes = classBytes.get(name);
        if (bytes == null) {
            throw new ClassNotFoundException(name);
        }

        int packageSeparator = name.lastIndexOf('.');
        if (packageSeparator >= 0) {
            String packageName = name.substring(0, packageSeparator);
            if (getDefinedPackage(packageName) == null) {
                definePackage(packageName, null, null, null, null, null, null, null);
            }
        }

        return defineClass(name, bytes, 0, bytes.length);
    }

    @Override
    public void close() {
        classBytes.clear();
    }
}

