final class CiGcTuning {
    private static final AtomicBoolean CONFIGURED = new AtomicBoolean(false);
    private static final String CI_PROFILE = "ci";
    private static final String PROFILE_PROPERTY = "textd.profile";
    private static final String PERIODIC_INTERVAL = "G1PeriodicGCInterval";
    private static final String LOAD_THRESHOLD = "G1PeriodicGCSystemLoadThreshold";

    private CiGcTuning() {
    }

    static void configureIfNeeded() {
        if (!CI_PROFILE.equals(System.getProperty(PROFILE_PROPERTY))) {
            return;
        }
        if (!CONFIGURED.compareAndSet(false, true)) {
            return;
        }

        HotSpotDiagnosticMXBean diagnostics = ManagementFactory.getPlatformMXBean(HotSpotDiagnosticMXBean.class);
        tuneOption(diagnostics, PERIODIC_INTERVAL, "10");
        tuneOption(diagnostics, LOAD_THRESHOLD, "0.0");
    }

    private static void tuneOption(HotSpotDiagnosticMXBean diagnostics, String name, String value) {
        VMOption current = diagnostics.getVMOption(name);
        if (!current.getValue().equals(value)) {
            diagnostics.setVMOption(name, value);
        }
    }
}

